using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public class ApiTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ApiTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "fetch_api_data"), Description("Fetch data from an external API endpoint.")]
    public async Task<string> FetchApiData(
        [Description("Relative path to query (e.g. \"users/1\")")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = _httpClientFactory.CreateClient("ExternalApi");

        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Summarize the provided text.")]
    public static IEnumerable<PromptMessage> Summarize(
        [Description("The text to summarize")] string text,
        [Description("Desired detail level: brief | detailed")] string detailLevel = "brief")
    {
        var systemInstruction = detailLevel.ToLowerInvariant() switch
        {
            "detailed" => "You are an expert summarizer. Produce a thorough summary that "
                        + "preserves key details, supporting arguments, and nuances.",
            _ => "You are an expert summarizer. Produce a concise summary capturing only "
               + "the most important points in a few sentences.",
        };

        yield return new PromptMessage
        {
            Role = Role.User,
            Content = new Content { Type = "text", Text = $"{systemInstruction}\n\n---\n\n{text}" },
        };
    }
}

